import { 
    ChordCandidate, ViterbiNode, HIANote, AuditInputNote, AuditCandidate, AuditFactor,
    INTERVAL_NAMES, DECAY_PER_QUARTER, 
    PENALTY_MISSING_3RD, PENALTY_MISSING_5TH, BONUS_SEVENTH,
    PENALTY_MISSING_7TH, PENALTY_MISSING_6TH, PENALTY_MISSING_ALTERED_5TH,
    BONUS_ROOT_IN_BASS, PENALTY_THIRD_IN_BASS, PENALTY_FIFTH_IN_BASS, PENALTY_SEVENTH_IN_BASS,
    PENALTY_SUBTRACTION, PENALTY_FLOOR,
    WEIGHT_ROLE_ROOT, WEIGHT_ROLE_3RD, WEIGHT_ROLE_5TH, WEIGHT_ROLE_7TH
} from './hiaDefs';
import { getMetricWeight } from './hiaWeights';
import { getFormattedTime } from '../../midiHarmony';

function getRoleWeight(interval: number): number {
    switch(interval) {
        case 0: return WEIGHT_ROLE_ROOT;
        case 3: case 4: return WEIGHT_ROLE_3RD;
        case 6: case 8: return WEIGHT_ROLE_3RD; 
        case 7: return WEIGHT_ROLE_5TH; 
        case 9: return WEIGHT_ROLE_5TH; 
        case 10: case 11: return WEIGHT_ROLE_7TH;
        default: return 1.0;
    }
}

export function scoreCandidate(
    cand: ChordCandidate,
    beatStartTick: number,
    beatEndTick: number,
    beatMidTick: number,
    activeNotes: HIANote[],
    prevNode: ViterbiNode,
    cutoffTick: number,
    suspensionMap: Map<HIANote, boolean>,
    ppq: number,
    tsNum: number,
    tsDenom: number
): { finalScore: number, stepScore: number, auditCandidate: AuditCandidate, inputsLog: AuditInputNote[], assignedNotes: Set<HIANote> } {

    let quality = cand.baselineQ;
    const qualityLog: string[] = ["Base 1.0"];
    const assigned = new Set<HIANote>();
    const intervalsPresent = new Set<number>();

    let evidenceSum = 0;
    const evidenceLog: AuditFactor[] = [];

    let penaltySum = 0;
    const penaltyLog: AuditFactor[] = [];

    const inputsLog: AuditInputNote[] = []; 

    const isContinuation = (cand.name === prevNode.chord.name);

    for (const note of activeNotes) {
        const decayVal = (() => {
            const noteEnd = note.ticks + note.durationTicks;
            let distQuarters = 0;
            if (note.ticks >= beatEndTick) distQuarters = (note.ticks - beatEndTick) / ppq; 
            else if (noteEnd < beatMidTick) distQuarters = (beatMidTick - noteEnd) / ppq;
            return Math.max(0, 1 - (DECAY_PER_QUARTER * distQuarters));
        })();

        const isSusp = suspensionMap.get(note) || false;

        const auditNote: AuditInputNote = {
            name: note.name,
            midi: note.midi,
            durationQuarters: note.durationTicks / ppq, 
            metricWeight: getMetricWeight(note.ticks, ppq, tsNum, tsDenom),
            approachModifier: note.approachModifier, 
            decay: decayVal,
            finalSalience: note.baseSalience * decayVal,
            isSuspension: isSusp,
            voiceIndex: note.voiceIndex ?? -1,
            onsetFormatted: getFormattedTime(note.ticks, ppq, tsNum, tsDenom) 
        };

        if (!isContinuation && cutoffTick !== -1) {
            const isQuarterOrLonger = note.durationTicks >= ppq;
            if (note.ticks < cutoffTick && !isQuarterOrLonger) {
                let reason = "Exc. (Passing)";
                if (isSusp) reason = "Exc. (Sus)";
                else if (prevNode.chord.root !== -1) {
                        const prevInterval = (note.midi - prevNode.chord.root + 12) % 12;
                        if (prevNode.chord.intervals.includes(prevInterval)) reason = `Exc. (${prevNode.chord.name})`;
                }
                inputsLog.push({ ...auditNote, finalSalience: 0, isExcluded: true, exclusionReason: reason });
                continue; 
            }
        }

        const rawSalience = auditNote.finalSalience;
        if (rawSalience <= 0) {
             inputsLog.push(auditNote);
             continue;
        }

        const pc = note.midi % 12;
        const interval = (pc - cand.root + 12) % 12;

        if (cand.intervals.includes(interval)) {
            const roleWeight = getRoleWeight(interval);
            const weightedSalience = rawSalience * roleWeight;
            evidenceSum += weightedSalience;
            intervalsPresent.add(interval);
            assigned.add(note);
            evidenceLog.push({ noteName: note.name, label: `${INTERVAL_NAMES[interval]} (x${roleWeight})`, value: weightedSalience });
            inputsLog.push({ ...auditNote, roleWeight, weightedSalience });
        } else if (!isSusp) {
            const penaltyVal = Math.max(rawSalience - PENALTY_SUBTRACTION, PENALTY_FLOOR);
            penaltySum += penaltyVal; 
            penaltyLog.push({ noteName: note.name, label: "Non-CT", value: penaltyVal });
            inputsLog.push(auditNote);
        } else {
             inputsLog.push(auditNote); 
        }
    }

    if (!intervalsPresent.has(3) && !intervalsPresent.has(4)) {
            quality -= PENALTY_MISSING_3RD;
            qualityLog.push(`No 3rd (-${PENALTY_MISSING_3RD})`);
    }

    const qLower = cand.quality.toLowerCase();
    const isDiminished = qLower.includes('dim') || cand.quality === 'm7b5';
    const isAugmented = qLower.includes('aug');
    const isSeventh = cand.quality.includes('7');
    const isSixth = cand.quality.includes('6');

    if (isDiminished) {
        if (!intervalsPresent.has(6)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No dim5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else if (isAugmented) {
        if (!intervalsPresent.has(8)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No aug5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else {
        if (!intervalsPresent.has(7)) {
            quality -= PENALTY_MISSING_5TH;
            qualityLog.push(`No 5th (-${PENALTY_MISSING_5TH})`);
        }
    }

    if (isSeventh) {
        let has7th = false;
        if (cand.quality === 'dim7') {
            if (intervalsPresent.has(9)) has7th = true; 
        } else if (intervalsPresent.has(10) || intervalsPresent.has(11)) {
            has7th = true; 
        }

        if (!has7th) {
            quality -= PENALTY_MISSING_7TH;
            qualityLog.push(`No 7th (-${PENALTY_MISSING_7TH})`);
        } else {
            quality += BONUS_SEVENTH;
            qualityLog.push(`7th Pres (+${BONUS_SEVENTH})`);
        }
    }

    if (isSixth && !intervalsPresent.has(9)) {
        quality -= PENALTY_MISSING_6TH;
        qualityLog.push(`No 6th (-${PENALTY_MISSING_6TH})`);
    }

    if (assigned.size > 0) {
        let lowestMidi = Infinity;
        let lowestNote: HIANote | null = null;
        assigned.forEach(n => {
            if (n.midi < lowestMidi) { lowestMidi = n.midi; lowestNote = n; }
        });

        if (lowestNote) {
            const bassInterval = (lowestNote.midi - cand.root + 12) % 12;
            if (bassInterval === 0) {
                quality += BONUS_ROOT_IN_BASS;
                qualityLog.push(`Root Inv (+${BONUS_ROOT_IN_BASS})`);
            }
            else if (bassInterval === 3 || bassInterval === 4) {
                quality -= PENALTY_THIRD_IN_BASS;
                qualityLog.push(`3rd Inv ${lowestNote.name} (-${PENALTY_THIRD_IN_BASS})`);
            }
            else if (bassInterval === 6 || bassInterval === 7 || bassInterval === 8) {
                quality -= PENALTY_FIFTH_IN_BASS;
                qualityLog.push(`5th Inv ${lowestNote.name} (-${PENALTY_FIFTH_IN_BASS})`);
            }
            else if (bassInterval === 9 || bassInterval === 10 || bassInterval === 11) {
                quality -= PENALTY_SEVENTH_IN_BASS;
                qualityLog.push(`7th/6th Inv ${lowestNote.name} (-${PENALTY_SEVENTH_IN_BASS})`);
            }
        }
    }

    // Safety: Ensure Quality doesn't go below a reasonable floor or become negative
    // which would invert the scoring logic (making penalties desirable).
    quality = Math.max(0.1, quality);

    // Formula: (Evidence - Penalty) * Quality
    const rawStepScore = evidenceSum - penaltySum;
    const finalStepScore = rawStepScore * quality;

    // Accumulate total
    const totalScore = prevNode.score + finalStepScore;

    return {
        finalScore: totalScore,
        stepScore: finalStepScore,
        auditCandidate: {
            name: cand.name,
            qualityScore: quality,
            qualityLog,
            evidenceTotal: evidenceSum,
            evidenceBreakdown: evidenceLog,
            penaltyTotal: penaltySum,
            penaltyBreakdown: penaltyLog,
            pathScore: prevNode.score,
            stepScore: finalStepScore,
            finalScore: totalScore
        },
        inputsLog,
        assignedNotes: assigned
    };
}

import { ChordEvent } from '../../../types';
import { AuditLogStep, AuditCandidate, AuditInputNote, AuditFactor } from './hia/hiaDefs';

const VOICES = ['S', 'A', 'T', 'B'];

function getVoiceCode(idx: number): string {
    if (idx === 0) return 'S';
    if (idx === 1) return 'A';
    if (idx === 2) return 'T';
    if (idx === 3) return 'B';
    return `V${idx+1}`;
}

function formatDuration(quarters: number): string {
    if (Math.abs(quarters - 4.0) < 0.05) return "1/1";
    if (Math.abs(quarters - 3.0) < 0.05) return "1/2.";
    if (Math.abs(quarters - 2.0) < 0.05) return "1/2";
    if (Math.abs(quarters - 1.5) < 0.05) return "1/4.";
    if (Math.abs(quarters - 1.0) < 0.05) return "1/4";
    if (Math.abs(quarters - 0.75) < 0.05) return "1/8.";
    if (Math.abs(quarters - 0.5) < 0.05) return "1/8";
    if (Math.abs(quarters - 0.25) < 0.05) return "1/16";
    return quarters.toFixed(2);
}

function formatHeaderTime(str: string): string {
    return str.replace('M', 'Measure ').replace('B', 'Beat ');
}

function formatFactorLine(f: AuditFactor, sign: string): string {
    const safeName = f.noteName || "Unknown";
    return `- ${sign} ${safeName} (${f.label}) : ${f.value.toFixed(2)}`;
}

function formatWinningChordBlock(cand: AuditCandidate): string {
    let out = `**Winning Chord: ${cand.name}**\n`;

    out += `\n**Chord Notes (Evidence)**\n`;
    if (cand.evidenceBreakdown.length > 0) {
        cand.evidenceBreakdown.forEach(f => out += `${formatFactorLine(f, '+')}\n`);
    }
    out += `= **${cand.evidenceTotal.toFixed(2)}**\n`;

    out += `\n**Non Chord Notes (Penalty)**\n`;
    if (cand.penaltyBreakdown.length > 0) {
        cand.penaltyBreakdown.forEach(f => out += `${formatFactorLine(f, '-')}\n`);
    } else {
        out += `(None)\n`;
    }
    out += `= **-${cand.penaltyTotal.toFixed(2)}**\n`;

    out += `\n**Quality Modifiers** (Applied to Final Path Score)\n`;
    out += `- Base Quality: ${cand.qualityScore.toFixed(2)}\n`;
    cand.qualityLog.forEach(log => {
        if (log !== "Base 1.0") out += `- ${log}\n`;
    });

    out += `\n**Step Calculation:**\n`;
    out += `Score = (Evidence - Penalty) * Quality\n`;
    out += `Score = (${cand.evidenceTotal.toFixed(2)} - ${cand.penaltyTotal.toFixed(2)}) * ${cand.qualityScore.toFixed(2)}\n`;
    out += `**Step Score:** ${cand.stepScore.toFixed(2)}\n`;
    out += `**Path Accumulation:** ${cand.finalScore.toFixed(2)}\n`;

    return out;
}

function formatRunnersUp(candidates: AuditCandidate[]): string {
    if (!candidates || candidates.length === 0) return "";
    let out = `\n### Runners Up (Alternatives)\n\n`;
    out += `Rank | Chord | Total | Step | Quality | Evid | Pen\n`;
    out += `--- | --- | --- | --- | --- | --- | ---\n`;

    candidates.forEach((c, i) => {
        out += `${i+1} | ${c.name} | ${c.finalScore.toFixed(2)} | ${c.stepScore.toFixed(2)} | ${c.qualityScore.toFixed(2)} | ${c.evidenceTotal.toFixed(2)} | -${c.penaltyTotal.toFixed(2)}\n`;
    });
    return out;
}

export function generateHIAAuditLog(chords: ChordEvent[]): string {
    if (!chords || chords.length === 0) return "";

    let report = "";
    let lastReportedScore = 0;

    chords.forEach((c, idx) => {
        if (!c.debugInfo) return;

        let step: AuditLogStep | null = null;
        try {
            step = JSON.parse(c.debugInfo);
        } catch (e) {
            report += `[ERR] Could not parse debug info for ${c.formattedTime}\n`;
            return;
        }

        if (!step) return;

        report += `\n## ${formatHeaderTime(step.formattedTime)}\n\n`;

        report += `### Context\n`;
        report += `**Previous Chord:** ${step.prevChord}\n`;

        // Show how much score was added while the previous chord was held
        const accumulatedInHold = step.winner.pathScore - lastReportedScore;
        if (idx > 0 && accumulatedInHold > 0.01) {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)} (+${accumulatedInHold.toFixed(2)} accumulated during hold)\n`;
        } else {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)}\n`;
        }
        report += `\n`;

        report += `### Inputs\n\n`;
        report += `Voc & Onset | Note | Dur | Met | Appr | Decay | Final Sal | Flags\n`;
        report += `----|------|------|------|------|------|------|-------\n`;

        if (step.inputs.length === 0) {
            report += `(No active inputs)\n`;
        } else {
            step.inputs.forEach((n: AuditInputNote) => {
                const vLabel = getVoiceCode(n.voiceIndex);
                const vocOnset = `${vLabel}: ${n.onsetFormatted}`;
                const safeName = n.name || "???";
                const dur = formatDuration(n.durationQuarters);
                const met = n.metricWeight.toFixed(1);
                const appr = n.approachModifier.toFixed(2); 
                const decay = n.decay.toFixed(2);
                const score = n.finalSalience.toFixed(2);

                let flags = "";
                if (n.isExcluded) flags = n.exclusionReason || "Excluded";
                else if (n.isSuspension) flags = "**Susp**";

                report += `${vocOnset} | ${safeName} | ${dur} | ${met} | ${appr} | ${decay} | ${score} | ${flags}\n`;
            });
        }
        report += `\n`;

        report += `### Winner Selection\n\n`;
        report += formatWinningChordBlock(step.winner);
        lastReportedScore = step.winner.finalScore;

        report += formatRunnersUp(step.runnersUp);
        report += `\n`;
    });

    return report;
}

import { RawNote } from '../../../../types';

// --- Weights & Constants (Protected) ---
export const WEIGHT_STRONG_BEAT = 1.2;     // Measure Downbeat
export const WEIGHT_MEDIUM_BEAT = 1.0;     // Secondary Strong Beat
export const WEIGHT_WEAK_BEAT = 0.75;      // Weak Beats
export const WEIGHT_SUBDIVISION = 0.6;     // Main Subdivisions
export const WEIGHT_OFF_BEAT = 0.5;        // Off-grid

export const MOD_APPROACH_LEAP = 1.2;
export const MOD_APPROACH_STEP = 0.8;
export const MOD_APPROACH_OTHER = 1.0;

export const DECAY_PER_QUARTER = 0.25;

// Penalty Constants (New Formula)
export const PENALTY_SUBTRACTION = 0.15;
export const PENALTY_FLOOR = 0.02;

// Role Weights (Evidence)
export const WEIGHT_ROLE_ROOT = 1.1;
export const WEIGHT_ROLE_3RD = 1.05; // Includes Altered 5ths
export const WEIGHT_ROLE_7TH = 0.95; // Includes Extensions
export const WEIGHT_ROLE_5TH = 0.90; // Includes 6ths

// Inversion Weights (Still relevant for Quality Score)
export const BONUS_ROOT_IN_BASS = 0.1;
export const PENALTY_THIRD_IN_BASS = 0.1;
export const PENALTY_FIFTH_IN_BASS = 0.2;
export const PENALTY_SEVENTH_IN_BASS = 0.25;

// Strict Structural Penalties for Quality Score
export const PENALTY_MISSING_3RD = 0.25; 
export const PENALTY_MISSING_5TH = 0.1;
export const BONUS_SEVENTH = 0.05; 
export const PENALTY_MISSING_7TH = 2.0;
export const PENALTY_MISSING_6TH = 2.0;
export const PENALTY_MISSING_ALTERED_5TH = 2.0; 

export const BEAM_WIDTH = 25;

export const INTERVAL_NAMES = ['Root', 'm2', 'M2', 'm3', 'M3', 'P4', 'TT', 'P5', 'm6', 'M6', 'm7', 'M7'];
export const CONSONANT_INTERVALS = [0, 3, 4, 7, 8, 9]; 
export const DISSONANT_INTERVALS = [1, 2, 5, 6, 10, 11]; 

// --- Interfaces ---

export interface NoteLinks {
    prev: RawNote | null;
    next: RawNote | null;
}

export interface HIANote extends RawNote {
    baseSalience: number;
    voicePrevMidi?: number;
    approachModifier: number; 
}

export interface BeatWindow {
    index: number;
    startTick: number;
    midTick: number;
    endTick: number;
    activeNotes: HIANote[];
}

export interface ChordCandidate {
    root: number;
    quality: string;
    intervals: number[];
    bass: number;
    baselineQ: number;
    name: string;
}

// --- Deep Audit Interfaces ---

export interface AuditInputNote {
    name: string;
    midi: number;
    durationQuarters: number;
    metricWeight: number;
    approachModifier: number;
    decay: number;
    finalSalience: number; // Base * Decay
    roleWeight?: number;   // The weight applied based on interval role
    weightedSalience?: number; // Final evidence value
    isSuspension: boolean;
    voiceIndex: number;
    onsetFormatted: string; 
    isExcluded?: boolean;
    exclusionReason?: string;
}

export interface AuditFactor {
    noteName: string; 
    label: string; 
    value: number; 
}

export interface AuditCandidate {
    name: string; 
    qualityScore: number;
    qualityLog: string[]; 
    evidenceTotal: number;
    evidenceBreakdown: AuditFactor[];
    penaltyTotal: number;
    penaltyBreakdown: AuditFactor[];
    pathScore: number; 
    stepScore: number; 
    finalScore: number; 
}

export interface AuditLogStep {
    tick: number;
    formattedTime: string;
    prevChord: string; 
    inputs: AuditInputNote[];
    winner: AuditCandidate;
    runnersUp: AuditCandidate[];
}

export interface ViterbiNode {
    chord: ChordCandidate;
    score: number;
    path: ViterbiNode[]; 
    assignedNotes: Set<HIANote>;
    audit: AuditLogStep; 
    _prevNodeIdx: number;
}

import { RawNote } from '../../../../types';
import { HIANote, NoteLinks, CONSONANT_INTERVALS, DISSONANT_INTERVALS } from './hiaDefs';

export function getPhysicalBass(notes: RawNote[], time: number): number | null {
    let minMidi = Infinity;
    let found = false;
    for (const n of notes) {
        if (n.ticks <= time && (n.ticks + n.durationTicks) > time) {
            if (n.midi < minMidi) { minMidi = n.midi; found = true; }
        }
    }
    return found ? minMidi : null;
}

// Build linked list for voice leading checks
export function buildVoiceLinks(notes: RawNote[]): Map<RawNote, NoteLinks> {
    const links = new Map<RawNote, NoteLinks>();
    const byVoice: Record<number, RawNote[]> = {};

    // Group by voice
    notes.forEach(n => {
        const v = n.voiceIndex ?? -1;
        if (!byVoice[v]) byVoice[v] = [];
        byVoice[v].push(n);
    });

    // Link
    Object.values(byVoice).forEach(voiceNotes => {
        voiceNotes.sort((a,b) => a.ticks - b.ticks);
        for(let i=0; i<voiceNotes.length; i++) {
            const curr = voiceNotes[i];
            const prev = i > 0 ? voiceNotes[i-1] : null;
            const next = i < voiceNotes.length - 1 ? voiceNotes[i+1] : null;
            links.set(curr, { prev, next });
        }
    });
    return links;
}

/**
 * Strict Suspension Check
 */
export function isSuspension(
    note: HIANote, 
    beatStart: number, 
    beatEnd: number,
    prevBassMidi: number | null,
    currBassMidi: number | null,
    links: NoteLinks
): boolean {
    if (prevBassMidi === null || currBassMidi === null) return false;

    // RULE 0: Bass must move to create the dissonance against the held note
    // If bass is static, any dissonance is a passing tone or neighbor, not a suspension
    if (prevBassMidi === currBassMidi) return false;

    // --- 1. Preparation Check ---
    let prepMidi = -1;

    // Case A: Tied/Held Note (Started before beat)
    if (note.ticks < beatStart) {
        prepMidi = note.midi;
    }
    // Case B: Repeated Note (Started exactly on beat, check previous note)
    else if (note.ticks === beatStart) {
        // Must be a true legato repetition
        if (links.prev && links.prev.midi === note.midi && (links.prev.ticks + links.prev.durationTicks) >= beatStart) {
            prepMidi = links.prev.midi;
        } else {
            return false; // Not prepared
        }
    } else {
        return false; // Started late in the beat, not a suspension
    }

    // Verify Prep Consonance (against PREVIOUS bass)
    const prepInterval = (prepMidi - prevBassMidi + 1200) % 12;
    if (!CONSONANT_INTERVALS.includes(prepInterval)) return false;

    // --- 2. Dissonance Check ---
    // The current note must be dissonant against the NEW bass
    const currentInterval = (note.midi - currBassMidi + 1200) % 12;
    if (!DISSONANT_INTERVALS.includes(currentInterval)) return false;

    // --- 3. Resolution Check ---
    const resolutionNote = links.next;
    if (!resolutionNote) return false;

    // Verify Resolution Consonance against the CURRENT Bass
    // Resolution implies the bass stays static while the voice moves down
    const resInterval = (resolutionNote.midi - currBassMidi + 1200) % 12;
    if (!CONSONANT_INTERVALS.includes(resInterval)) return false;

    // Resolution: Must be a move, but stepwise constraint removed per user request.
    const move = resolutionNote.midi - note.midi;
    if (move === 0) return false; 

    return true;
}

import { 
    ChordCandidate, ViterbiNode, HIANote, AuditInputNote, AuditCandidate, AuditFactor,
    INTERVAL_NAMES, DECAY_PER_QUARTER, 
    PENALTY_MISSING_3RD, PENALTY_MISSING_5TH, BONUS_SEVENTH,
    PENALTY_MISSING_7TH, PENALTY_MISSING_6TH, PENALTY_MISSING_ALTERED_5TH,
    BONUS_ROOT_IN_BASS, PENALTY_THIRD_IN_BASS, PENALTY_FIFTH_IN_BASS, PENALTY_SEVENTH_IN_BASS,
    PENALTY_SUBTRACTION, PENALTY_FLOOR,
    WEIGHT_ROLE_ROOT, WEIGHT_ROLE_3RD, WEIGHT_ROLE_5TH, WEIGHT_ROLE_7TH
} from './hiaDefs';
import { getMetricWeight } from './hiaWeights';
import { getFormattedTime } from '../../midiHarmony';

function getRoleWeight(interval: number): number {
    switch(interval) {
        case 0: return WEIGHT_ROLE_ROOT;
        case 3: case 4: return WEIGHT_ROLE_3RD;
        case 6: case 8: return WEIGHT_ROLE_3RD; 
        case 7: return WEIGHT_ROLE_5TH; 
        case 9: return WEIGHT_ROLE_5TH; 
        case 10: case 11: return WEIGHT_ROLE_7TH;
        default: return 1.0;
    }
}

export function scoreCandidate(
    cand: ChordCandidate,
    beatStartTick: number,
    beatEndTick: number,
    beatMidTick: number,
    activeNotes: HIANote[],
    prevNode: ViterbiNode,
    cutoffTick: number,
    suspensionMap: Map<HIANote, boolean>,
    ppq: number,
    tsNum: number,
    tsDenom: number
): { finalScore: number, stepScore: number, auditCandidate: AuditCandidate, inputsLog: AuditInputNote[], assignedNotes: Set<HIANote> } {

    // Set Base Quality to 0.9 as requested
    let quality = 0.9;
    const qualityLog: string[] = ["Base 0.9"];
    const assigned = new Set<HIANote>();
    const intervalsPresent = new Set<number>();

    let evidenceSum = 0;
    const evidenceLog: AuditFactor[] = [];

    let penaltySum = 0;
    const penaltyLog: AuditFactor[] = [];

    const inputsLog: AuditInputNote[] = []; 

    const isContinuation = (cand.name === prevNode.chord.name);

    for (const note of activeNotes) {
        const decayVal = (() => {
            const noteEnd = note.ticks + note.durationTicks;
            let distQuarters = 0;
            if (note.ticks >= beatEndTick) distQuarters = (note.ticks - beatEndTick) / ppq; 
            else if (noteEnd < beatMidTick) distQuarters = (beatMidTick - noteEnd) / ppq;
            return Math.max(0, 1 - (DECAY_PER_QUARTER * distQuarters));
        })();

        const isSusp = suspensionMap.get(note) || false;

        const auditNote: AuditInputNote = {
            name: note.name,
            midi: note.midi,
            durationQuarters: note.durationTicks / ppq, 
            metricWeight: getMetricWeight(note.ticks, ppq, tsNum, tsDenom),
            approachModifier: note.approachModifier, 
            decay: decayVal,
            finalSalience: note.baseSalience * decayVal,
            isSuspension: isSusp,
            voiceIndex: note.voiceIndex ?? -1,
            onsetFormatted: getFormattedTime(note.ticks, ppq, tsNum, tsDenom) 
        };

        if (!isContinuation && cutoffTick !== -1) {
            const isQuarterOrLonger = note.durationTicks >= ppq;
            if (note.ticks < cutoffTick && !isQuarterOrLonger) {
                let reason = "Exc. (Passing)";
                if (isSusp) reason = "Exc. (Sus)";
                else if (prevNode.chord.root !== -1) {
                        const prevInterval = (note.midi - prevNode.chord.root + 12) % 12;
                        if (prevNode.chord.intervals.includes(prevInterval)) reason = `Exc. (${prevNode.chord.name})`;
                }
                inputsLog.push({ ...auditNote, finalSalience: 0, isExcluded: true, exclusionReason: reason });
                continue; 
            }
        }

        const rawSalience = auditNote.finalSalience;
        if (rawSalience <= 0) {
             inputsLog.push(auditNote);
             continue;
        }

        const pc = note.midi % 12;
        const interval = (pc - cand.root + 12) % 12;

        if (cand.intervals.includes(interval)) {
            const roleWeight = getRoleWeight(interval);
            const weightedSalience = rawSalience * roleWeight;
            evidenceSum += weightedSalience;
            intervalsPresent.add(interval);
            assigned.add(note);
            evidenceLog.push({ noteName: note.name, label: `${INTERVAL_NAMES[interval]} (x${roleWeight})`, value: weightedSalience });
            inputsLog.push({ ...auditNote, roleWeight, weightedSalience });
        } else if (!isSusp) {
            const penaltyVal = Math.max(rawSalience - PENALTY_SUBTRACTION, PENALTY_FLOOR);
            penaltySum += penaltyVal; 
            penaltyLog.push({ noteName: note.name, label: "Non-CT", value: penaltyVal });
            inputsLog.push(auditNote);
        } else {
             inputsLog.push(auditNote); 
        }
    }

    if (!intervalsPresent.has(3) && !intervalsPresent.has(4)) {
            quality -= PENALTY_MISSING_3RD;
            qualityLog.push(`No 3rd (-${PENALTY_MISSING_3RD})`);
    }

    const qLower = cand.quality.toLowerCase();
    const isDiminished = qLower.includes('dim') || cand.quality === 'm7b5';
    const isAugmented = qLower.includes('aug');
    const isSeventh = cand.quality.includes('7');
    const isSixth = cand.quality.includes('6');

    if (isDiminished) {
        if (!intervalsPresent.has(6)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No dim5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else if (isAugmented) {
        if (!intervalsPresent.has(8)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No aug5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else {
        if (!intervalsPresent.has(7)) {
            quality -= PENALTY_MISSING_5TH;
            qualityLog.push(`No 5th (-${PENALTY_MISSING_5TH})`);
        }
    }

    if (isSeventh) {
        let has7th = false;
        if (cand.quality === 'dim7') {
            if (intervalsPresent.has(9)) has7th = true; 
        } else if (intervalsPresent.has(10) || intervalsPresent.has(11)) {
            has7th = true; 
        }

        if (!has7th) {
            quality -= PENALTY_MISSING_7TH;
            qualityLog.push(`No 7th (-${PENALTY_MISSING_7TH})`);
        } else {
            quality += BONUS_SEVENTH;
            qualityLog.push(`7th Pres (+${BONUS_SEVENTH})`);
        }
    }

    if (isSixth && !intervalsPresent.has(9)) {
        quality -= PENALTY_MISSING_6TH;
        qualityLog.push(`No 6th (-${PENALTY_MISSING_6TH})`);
    }

    if (assigned.size > 0) {
        let lowestMidi = Infinity;
        let lowestNote: HIANote | null = null;
        assigned.forEach(n => {
            if (n.midi < lowestMidi) { lowestMidi = n.midi; lowestNote = n; }
        });

        if (lowestNote) {
            const bassInterval = (lowestNote.midi - cand.root + 12) % 12;
            if (bassInterval === 0) {
                quality += BONUS_ROOT_IN_BASS;
                qualityLog.push(`Root Inv (+${BONUS_ROOT_IN_BASS})`);
            }
            else if (bassInterval === 3 || bassInterval === 4) {
                quality -= PENALTY_THIRD_IN_BASS;
                qualityLog.push(`3rd Inv ${lowestNote.name} (-${PENALTY_THIRD_IN_BASS})`);
            }
            else if (bassInterval === 6 || bassInterval === 7 || bassInterval === 8) {
                quality -= PENALTY_FIFTH_IN_BASS;
                qualityLog.push(`5th Inv ${lowestNote.name} (-${PENALTY_FIFTH_IN_BASS})`);
            }
            else if (bassInterval === 9 || bassInterval === 10 || bassInterval === 11) {
                quality -= PENALTY_SEVENTH_IN_BASS;
                qualityLog.push(`7th/6th Inv ${lowestNote.name} (-${PENALTY_SEVENTH_IN_BASS})`);
            }
        }
    }

    // Formula Update: (Evidence * Quality) - Penalty
    // Note: Quality is no longer clamped, so it can be negative.
    const finalStepScore = (evidenceSum * quality) - penaltySum;

    // Accumulate total
    const totalScore = prevNode.score + finalStepScore;

    return {
        finalScore: totalScore,
        stepScore: finalStepScore,
        auditCandidate: {
            name: cand.name,
            qualityScore: quality,
            qualityLog,
            evidenceTotal: evidenceSum,
            evidenceBreakdown: evidenceLog,
            penaltyTotal: penaltySum,
            penaltyBreakdown: penaltyLog,
            pathScore: prevNode.score,
            stepScore: finalStepScore,
            finalScore: totalScore
        },
        inputsLog,
        assignedNotes: assigned
    };
}

import { ChordEvent } from '../../../types';
import { AuditLogStep, AuditCandidate, AuditInputNote, AuditFactor } from './hia/hiaDefs';

const VOICES = ['S', 'A', 'T', 'B'];

function getVoiceCode(idx: number): string {
    if (idx === 0) return 'S';
    if (idx === 1) return 'A';
    if (idx === 2) return 'T';
    if (idx === 3) return 'B';
    return `V${idx+1}`;
}

function formatDuration(quarters: number): string {
    if (Math.abs(quarters - 4.0) < 0.05) return "1/1";
    if (Math.abs(quarters - 3.0) < 0.05) return "1/2.";
    if (Math.abs(quarters - 2.0) < 0.05) return "1/2";
    if (Math.abs(quarters - 1.5) < 0.05) return "1/4.";
    if (Math.abs(quarters - 1.0) < 0.05) return "1/4";
    if (Math.abs(quarters - 0.75) < 0.05) return "1/8.";
    if (Math.abs(quarters - 0.5) < 0.05) return "1/8";
    if (Math.abs(quarters - 0.25) < 0.05) return "1/16";
    return quarters.toFixed(2);
}

function formatHeaderTime(str: string): string {
    return str.replace('M', 'Measure ').replace('B', 'Beat ');
}

function formatFactorLine(f: AuditFactor, sign: string): string {
    const safeName = f.noteName || "Unknown";
    return `- ${sign} ${safeName} (${f.label}) : ${f.value.toFixed(2)}`;
}

function formatWinningChordBlock(cand: AuditCandidate): string {
    let out = `**Winning Chord: ${cand.name}**\n`;

    out += `\n**Chord Notes (Evidence)**\n`;
    if (cand.evidenceBreakdown.length > 0) {
        cand.evidenceBreakdown.forEach(f => out += `${formatFactorLine(f, '+')}\n`);
    }
    out += `= **${cand.evidenceTotal.toFixed(2)}**\n`;

    out += `\n**Non Chord Notes (Penalty)**\n`;
    if (cand.penaltyBreakdown.length > 0) {
        cand.penaltyBreakdown.forEach(f => out += `${formatFactorLine(f, '-')}\n`);
    } else {
        out += `(None)\n`;
    }
    out += `= **-${cand.penaltyTotal.toFixed(2)}**\n`;

    out += `\n**Quality Modifiers** (Applied to Evidence)\n`;
    out += `- Base Quality: 0.90\n`;
    cand.qualityLog.forEach(log => {
        if (log !== "Base 1.0" && log !== "Base 0.9") out += `- ${log}\n`;
    });
    out += `= **${cand.qualityScore.toFixed(2)}**\n`;

    out += `\n**Step Calculation:**\n`;
    out += `Score = (Evidence * Quality) - Penalty\n`;
    out += `Score = (${cand.evidenceTotal.toFixed(2)} * ${cand.qualityScore.toFixed(2)}) - ${cand.penaltyTotal.toFixed(2)}\n`;
    out += `**Step Score:** ${cand.stepScore.toFixed(2)}\n`;
    out += `**Path Accumulation:** ${cand.finalScore.toFixed(2)}\n`;

    return out;
}

function formatRunnersUp(candidates: AuditCandidate[]): string {
    if (!candidates || candidates.length === 0) return "";
    let out = `\n### Runners Up (Alternatives)\n\n`;
    out += `Rank | Chord | Total | Step | Quality | Evid | Pen\n`;
    out += `--- | --- | --- | --- | --- | --- | ---\n`;

    candidates.forEach((c, i) => {
        out += `${i+1} | ${c.name} | ${c.finalScore.toFixed(2)} | ${c.stepScore.toFixed(2)} | ${c.qualityScore.toFixed(2)} | ${c.evidenceTotal.toFixed(2)} | -${c.penaltyTotal.toFixed(2)}\n`;
    });
    return out;
}

export function generateHIAAuditLog(chords: ChordEvent[]): string {
    if (!chords || chords.length === 0) return "";

    let report = "";
    let lastReportedScore = 0;

    chords.forEach((c, idx) => {
        if (!c.debugInfo) return;

        let step: AuditLogStep | null = null;
        try {
            step = JSON.parse(c.debugInfo);
        } catch (e) {
            report += `[ERR] Could not parse debug info for ${c.formattedTime}\n`;
            return;
        }

        if (!step) return;

        report += `\n## ${formatHeaderTime(step.formattedTime)}\n\n`;

        report += `### Context\n`;
        report += `**Previous Chord:** ${step.prevChord}\n`;

        // Show how much score was added while the previous chord was held
        const accumulatedInHold = step.winner.pathScore - lastReportedScore;
        if (idx > 0 && accumulatedInHold > 0.01) {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)} (+${accumulatedInHold.toFixed(2)} accumulated during hold)\n`;
        } else {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)}\n`;
        }
        report += `\n`;

        report += `### Inputs\n\n`;
        report += `Voc & Onset | Note | Dur | Met | Appr | Decay | Final Sal | Flags\n`;
        report += `----|------|------|------|------|------|------|-------\n`;

        if (step.inputs.length === 0) {
            report += `(No active inputs)\n`;
        } else {
            step.inputs.forEach((n: AuditInputNote) => {
                const vLabel = getVoiceCode(n.voiceIndex);
                const vocOnset = `${vLabel}: ${n.onsetFormatted}`;
                const safeName = n.name || "???";
                const dur = formatDuration(n.durationQuarters);
                const met = n.metricWeight.toFixed(1);
                const appr = n.approachModifier.toFixed(2); 
                const decay = n.decay.toFixed(2);
                const score = n.finalSalience.toFixed(2);

                let flags = "";
                if (n.isExcluded) flags = n.exclusionReason || "Excluded";
                else if (n.isSuspension) flags = "**Susp**";

                report += `${vocOnset} | ${safeName} | ${dur} | ${met} | ${appr} | ${decay} | ${score} | ${flags}\n`;
            });
        }
        report += `\n`;

        report += `### Winner Selection\n\n`;
        report += formatWinningChordBlock(step.winner);
        lastReportedScore = step.winner.finalScore;

        report += formatRunnersUp(step.runnersUp);
        report += `\n`;
    });

    return report;
}

import { 
    ChordCandidate, ViterbiNode, HIANote, AuditInputNote, AuditCandidate, AuditFactor,
    INTERVAL_NAMES, DECAY_PER_QUARTER, 
    PENALTY_MISSING_3RD, PENALTY_MISSING_5TH, BONUS_SEVENTH,
    PENALTY_MISSING_7TH, PENALTY_MISSING_6TH, PENALTY_MISSING_ALTERED_5TH,
    BONUS_ROOT_IN_BASS, PENALTY_THIRD_IN_BASS, PENALTY_FIFTH_IN_BASS, PENALTY_SEVENTH_IN_BASS,
    PENALTY_SUBTRACTION, PENALTY_FLOOR,
    WEIGHT_ROLE_ROOT, WEIGHT_ROLE_3RD, WEIGHT_ROLE_5TH, WEIGHT_ROLE_7TH
} from './hiaDefs';
import { getMetricWeight } from './hiaWeights';
import { getFormattedTime } from '../../midiHarmony';

function getRoleWeight(interval: number): number {
    switch(interval) {
        case 0: return WEIGHT_ROLE_ROOT;
        case 3: case 4: return WEIGHT_ROLE_3RD;
        case 6: case 8: return WEIGHT_ROLE_3RD; 
        case 7: return WEIGHT_ROLE_5TH; 
        case 9: return WEIGHT_ROLE_5TH; 
        case 10: case 11: return WEIGHT_ROLE_7TH;
        default: return 1.0;
    }
}

export function scoreCandidate(
    cand: ChordCandidate,
    beatStartTick: number,
    beatEndTick: number,
    beatMidTick: number,
    activeNotes: HIANote[],
    prevNode: ViterbiNode,
    cutoffTick: number,
    suspensionMap: Map<HIANote, boolean>,
    ppq: number,
    tsNum: number,
    tsDenom: number
): { finalScore: number, stepScore: number, auditCandidate: AuditCandidate, inputsLog: AuditInputNote[], assignedNotes: Set<HIANote>, isValid: boolean } {

    // Set Base Quality to 0.9 as requested
    let quality = 0.9;
    const qualityLog: string[] = ["Base 0.9"];
    const assigned = new Set<HIANote>();
    const intervalsPresent = new Set<number>();

    let evidenceSum = 0;
    const evidenceLog: AuditFactor[] = [];

    let penaltySum = 0;
    const penaltyLog: AuditFactor[] = [];

    const inputsLog: AuditInputNote[] = []; 

    const isContinuation = (cand.name === prevNode.chord.name);

    for (const note of activeNotes) {
        const decayVal = (() => {
            const noteEnd = note.ticks + note.durationTicks;
            let distQuarters = 0;
            if (note.ticks >= beatEndTick) distQuarters = (note.ticks - beatEndTick) / ppq; 
            else if (noteEnd < beatMidTick) distQuarters = (beatMidTick - noteEnd) / ppq;
            return Math.max(0, 1 - (DECAY_PER_QUARTER * distQuarters));
        })();

        const isSusp = suspensionMap.get(note) || false;

        const auditNote: AuditInputNote = {
            name: note.name,
            midi: note.midi,
            durationQuarters: note.durationTicks / ppq, 
            metricWeight: getMetricWeight(note.ticks, ppq, tsNum, tsDenom),
            approachModifier: note.approachModifier, 
            decay: decayVal,
            finalSalience: note.baseSalience * decayVal,
            isSuspension: isSusp,
            voiceIndex: note.voiceIndex ?? -1,
            onsetFormatted: getFormattedTime(note.ticks, ppq, tsNum, tsDenom) 
        };

        if (!isContinuation && cutoffTick !== -1) {
            const isQuarterOrLonger = note.durationTicks >= ppq;
            if (note.ticks < cutoffTick && !isQuarterOrLonger) {
                let reason = "Exc. (Passing)";
                if (isSusp) reason = "Exc. (Sus)";
                else if (prevNode.chord.root !== -1) {
                        const prevInterval = (note.midi - prevNode.chord.root + 12) % 12;
                        if (prevNode.chord.intervals.includes(prevInterval)) reason = `Exc. (${prevNode.chord.name})`;
                }
                inputsLog.push({ ...auditNote, finalSalience: 0, isExcluded: true, exclusionReason: reason });
                continue; 
            }
        }

        const rawSalience = auditNote.finalSalience;
        if (rawSalience <= 0) {
             inputsLog.push(auditNote);
             continue;
        }

        const pc = note.midi % 12;
        const interval = (pc - cand.root + 12) % 12;

        if (cand.intervals.includes(interval)) {
            const roleWeight = getRoleWeight(interval);
            const weightedSalience = rawSalience * roleWeight;
            evidenceSum += weightedSalience;
            intervalsPresent.add(interval);
            assigned.add(note);
            evidenceLog.push({ noteName: note.name, label: `${INTERVAL_NAMES[interval]} (x${roleWeight})`, value: weightedSalience });
            inputsLog.push({ ...auditNote, roleWeight, weightedSalience });
        } else if (!isSusp) {
            const penaltyVal = Math.max(rawSalience - PENALTY_SUBTRACTION, PENALTY_FLOOR);
            penaltySum += penaltyVal; 
            penaltyLog.push({ noteName: note.name, label: "Non-CT", value: penaltyVal });
            inputsLog.push(auditNote);
        } else {
             inputsLog.push(auditNote); 
        }
    }

    let isValid = true;

    // Hard Constraint: Root must be present in evidence (not just assumed)
    if (!intervalsPresent.has(0)) {
        isValid = false;
        qualityLog.push("INVALID: No Root");
    }

    if (!intervalsPresent.has(3) && !intervalsPresent.has(4)) {
            quality -= PENALTY_MISSING_3RD;
            qualityLog.push(`No 3rd (-${PENALTY_MISSING_3RD})`);
    }

    const qLower = cand.quality.toLowerCase();
    const isDiminished = qLower.includes('dim') || cand.quality === 'm7b5';
    const isAugmented = qLower.includes('aug');
    const isSeventh = cand.quality.includes('7');
    const isSixth = cand.quality.includes('6');

    if (isDiminished) {
        if (!intervalsPresent.has(6)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No dim5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else if (isAugmented) {
        if (!intervalsPresent.has(8)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No aug5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else {
        if (!intervalsPresent.has(7)) {
            quality -= PENALTY_MISSING_5TH;
            qualityLog.push(`No 5th (-${PENALTY_MISSING_5TH})`);
        }
    }

    if (isSeventh) {
        let has7th = false;
        if (cand.quality === 'dim7') {
            if (intervalsPresent.has(9)) has7th = true; 
        } else if (intervalsPresent.has(10) || intervalsPresent.has(11)) {
            has7th = true; 
        }

        if (!has7th) {
            // Hard Constraint: 7th chords must have 7ths
            isValid = false;
            qualityLog.push("INVALID: No 7th");
        } else {
            quality += BONUS_SEVENTH;
            qualityLog.push(`7th Pres (+${BONUS_SEVENTH})`);
        }
    }

    if (isSixth && !intervalsPresent.has(9)) {
        quality -= PENALTY_MISSING_6TH;
        qualityLog.push(`No 6th (-${PENALTY_MISSING_6TH})`);
    }

    if (assigned.size > 0) {
        let lowestMidi = Infinity;
        let lowestNote: HIANote | null = null;
        assigned.forEach(n => {
            if (n.midi < lowestMidi) { lowestMidi = n.midi; lowestNote = n; }
        });

        if (lowestNote) {
            const bassInterval = (lowestNote.midi - cand.root + 12) % 12;
            if (bassInterval === 0) {
                quality += BONUS_ROOT_IN_BASS;
                qualityLog.push(`Root Inv (+${BONUS_ROOT_IN_BASS})`);
            }
            else if (bassInterval === 3 || bassInterval === 4) {
                quality -= PENALTY_THIRD_IN_BASS;
                qualityLog.push(`3rd Inv ${lowestNote.name} (-${PENALTY_THIRD_IN_BASS})`);
            }
            else if (bassInterval === 6 || bassInterval === 7 || bassInterval === 8) {
                quality -= PENALTY_FIFTH_IN_BASS;
                qualityLog.push(`5th Inv ${lowestNote.name} (-${PENALTY_FIFTH_IN_BASS})`);
            }
            else if (bassInterval === 9 || bassInterval === 10 || bassInterval === 11) {
                quality -= PENALTY_SEVENTH_IN_BASS;
                qualityLog.push(`7th/6th Inv ${lowestNote.name} (-${PENALTY_SEVENTH_IN_BASS})`);
            }
        }
    }

    // Formula Update: (Evidence * Quality) - Penalty
    // Note: Quality is no longer clamped, so it can be negative.
    const finalStepScore = (evidenceSum * quality) - penaltySum;

    // Accumulate total
    const totalScore = prevNode.score + finalStepScore;

    return {
        finalScore: totalScore,
        stepScore: finalStepScore,
        auditCandidate: {
            name: cand.name,
            qualityScore: quality,
            qualityLog,
            evidenceTotal: evidenceSum,
            evidenceBreakdown: evidenceLog,
            penaltyTotal: penaltySum,
            penaltyBreakdown: penaltyLog,
            pathScore: prevNode.score,
            stepScore: finalStepScore,
            finalScore: totalScore
        },
        inputsLog,
        assignedNotes: assigned,
        isValid
    };
}

import { RawNote, ChordEvent } from '../../../types';
import { getFormattedTime } from '../midiHarmony';
import { getStrictPitchName } from '../midiSpelling';
import { 
    BEAM_WIDTH, HIANote, BeatWindow, ViterbiNode
} from './hia/hiaDefs';
import { calculateBaseSalience } from './hia/hiaWeights';
import { getPhysicalBass, buildVoiceLinks, isSuspension } from './hia/hiaContext';
import { generateCandidates } from './hia/hiaCandidates';
import { scoreCandidate } from './hia/hiaScoring';

export function detectChordsHIA(notes: RawNote[], ppq: number, tsNum: number, tsDenom: number): ChordEvent[] {
    const sortedNotes = [...notes].sort((a,b) => a.ticks - b.ticks);
    const voiceTracker: Record<number, number> = {};

    const hiaNotes: HIANote[] = sortedNotes.map(n => {
        const v = n.voiceIndex ?? 0;
        const prev = voiceTracker[v];
        voiceTracker[v] = n.midi;
        return calculateBaseSalience(n, ppq, tsNum, tsDenom, prev);
    });

    const noteLinks = buildVoiceLinks(hiaNotes); 

    const beats: BeatWindow[] = [];
    const maxTick = Math.max(...hiaNotes.map(n => n.ticks + n.durationTicks));
    const ticksPerBeat = ppq; 
    const totalBeats = Math.ceil(maxTick / ticksPerBeat);

    for (let i = 0; i < totalBeats; i++) {
        const start = i * ticksPerBeat;
        const end = (i + 1) * ticksPerBeat;
        const mid = start + (ticksPerBeat / 2);
        const lookbackLimit = start - (4 * ppq);
        const lookaheadLimit = end + (2 * ticksPerBeat); 
        const active = hiaNotes.filter(n => {
            const noteEnd = n.ticks + n.durationTicks;
            return n.ticks < lookaheadLimit && noteEnd > lookbackLimit;
        });
        beats.push({ index: i, startTick: start, midTick: mid, endTick: end, activeNotes: active });
    }

    let beam: ViterbiNode[] = [{ 
        chord: { root: -1, quality: 'None', intervals: [], bass: -1, baselineQ: 0, name: 'Start' }, 
        score: 0, path: [], assignedNotes: new Set<HIANote>(),
        audit: { 
            tick: 0, formattedTime: '0:0', prevChord: 'None', inputs: [], 
            winner: { name: 'Start', qualityScore: 0, qualityLog: [], evidenceTotal: 0, evidenceBreakdown: [], penaltyTotal: 0, penaltyBreakdown: [], pathScore: 0, stepScore: 0, finalScore: 0 },
            runnersUp: [] 
        },
        _prevNodeIdx: -1
    }];

    for (const beat of beats) {
        const nextBeam: ViterbiNode[] = [];
        const presentRoots = new Set<number>();
        beat.activeNotes.forEach(n => presentRoots.add(n.midi % 12));

        const prevBassMidi = getPhysicalBass(sortedNotes, beat.startTick - 1);
        const currBassMidi = getPhysicalBass(sortedNotes, beat.startTick);
        const suspensionMap = new Map<HIANote, boolean>();

        if (beat.activeNotes.length >= 2) {
            beat.activeNotes.forEach(n => {
                const links = noteLinks.get(n) || { prev: null, next: null };
                const isSusp = isSuspension(n, beat.startTick, beat.endTick, prevBassMidi, currBassMidi, links);
                if (isSusp) suspensionMap.set(n, true);
            });
        }

        if (presentRoots.size === 0) {
            nextBeam.push(...beam.map(b => ({
                ...b, 
                score: b.score, 
                path: [...b.path, b], 
                assignedNotes: new Set<HIANote>(),
                audit: { 
                    tick: beat.startTick, 
                    formattedTime: getFormattedTime(beat.startTick, ppq, tsNum, tsDenom),
                    prevChord: b.chord.name,
                    inputs: [],
                    winner: { name: 'Silence', qualityScore: 0, qualityLog: [], evidenceTotal: 0, evidenceBreakdown: [], penaltyTotal: 0, penaltyBreakdown: [], pathScore: b.score, stepScore: 0, finalScore: b.score },
                    runnersUp: []
                },
                _prevNodeIdx: b._prevNodeIdx
            })));
            beam = nextBeam;
            continue;
        }

        const candidates = generateCandidates(presentRoots);
        const candidatesScores: ViterbiNode[] = [];

        beam.forEach((prevNode, prevIdx) => {
            let cutoffTick = -1;
            if (prevNode.assignedNotes.size > 0) {
                const sortedPrev = Array.from(prevNode.assignedNotes).sort((a,b) => {
                    if (a.ticks !== b.ticks) return a.ticks - b.ticks;
                    return (a.ticks + a.durationTicks) - (b.ticks + b.durationTicks);
                });
                const finalNote = sortedPrev[sortedPrev.length - 1];
                cutoffTick = finalNote.ticks + (finalNote.durationTicks / 2);
            }

            for (const cand of candidates) {
                const result = scoreCandidate(
                    cand, 
                    beat.startTick, 
                    beat.endTick, 
                    beat.midTick, 
                    beat.activeNotes, 
                    prevNode, 
                    cutoffTick, 
                    suspensionMap, 
                    ppq, tsNum, tsDenom
                );

                // Exclude Invalid Candidates (Missing Root / Missing 7th)
                if (!result.isValid) continue;

                candidatesScores.push({
                    chord: cand, 
                    score: result.finalScore, 
                    path: [...prevNode.path, prevNode],
                    assignedNotes: result.assignedNotes,
                    audit: {
                        tick: beat.startTick,
                        formattedTime: getFormattedTime(beat.startTick, ppq, tsNum, tsDenom),
                        prevChord: prevNode.chord.name,
                        inputs: result.inputsLog,
                        winner: result.auditCandidate,
                        runnersUp: []
                    },
                    _prevNodeIdx: prevIdx
                });
            }
        });

        candidatesScores.sort((a,b) => b.score - a.score);
        const seen = new Set<string>();
        const chosenNodes: ViterbiNode[] = [];

        for (const cs of candidatesScores) {
            if (seen.size >= BEAM_WIDTH) break;
            if (!seen.has(cs.chord.name)) { chosenNodes.push(cs); seen.add(cs.chord.name); }
        }

        chosenNodes.forEach(chosen => {
            const siblings = candidatesScores.filter(c => c.chord.name !== chosen.chord.name);
            chosen.audit.runnersUp = siblings.slice(0, 3).map(s => s.audit.winner);
        });

        if (chosenNodes.length === 0) {
             nextBeam.push(...beam.map(b => ({ ...b, path: [...b.path, b] })));
             beam = nextBeam;
        } else {
             beam = chosenNodes;
        }
    }

    const bestFinal = beam[0];
    if (!bestFinal) return [];

    const trace = [...bestFinal.path, bestFinal];
    trace.shift(); 

    const events: ChordEvent[] = [];
    let lastEvent: ChordEvent | null = null;

    trace.forEach((node, i) => {
        const beat = beats[i]; 
        const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
        const measure = Math.floor(beat.startTick / ticksPerMeasure) + 1;
        const uniqueConst = Array.from(new Set(Array.from(node.assignedNotes).map(n => n.name)));

        // We only create a "Chord Change" event for the UI/Summary, 
        // BUT we must preserve the audit log of the EXACT moment the event started.
        if (lastEvent && lastEvent.name === node.chord.name) return;

        const structuredDebug = JSON.stringify(node.audit);

        const evt: ChordEvent = {
            timestamp: beat.startTick / ppq, measure, formattedTime: getFormattedTime(beat.startTick, ppq, tsNum, tsDenom),
            name: node.chord.name, root: getStrictPitchName(node.chord.root).replace(/\d/g,''), quality: node.chord.quality,
            bass: getStrictPitchName(node.chord.bass).replace(/\d/g,''), ticks: beat.startTick,
            constituentNotes: uniqueConst, missingNotes: [], alternatives: [], debugInfo: structuredDebug
        };
        events.push(evt);
        lastEvent = evt;
    });
    return events;
}

import { ChordEvent } from '../../../types';
import { AuditLogStep, AuditCandidate, AuditFactor } from './hia/hiaDefs';

function formatFactorLine(f: AuditFactor): string {
    const safeName = f.noteName || "??";
    return `${safeName}`;
}

export function generateHIAAuditLog(chords: ChordEvent[]): string {
    if (!chords || chords.length === 0) return "";

    let report = `HIA v2.2 Audit Summary\n\n`;
    report += `| Time | Chord | Score | Path Score | Evidence Notes |\n`;
    report += `| :--- | :--- | :--- | :--- | :--- |\n`;

    chords.forEach((c) => {
        if (!c.debugInfo) return;

        let step: AuditLogStep | null = null;
        try {
            step = JSON.parse(c.debugInfo);
        } catch (e) {
            report += `| ${c.formattedTime} | ERR | - | - | - |\n`;
            return;
        }

        if (!step) return;

        const winner = step.winner;

        // Extract Evidence Notes for display
        const evidenceNotes = winner.evidenceBreakdown.map(f => f.noteName).join(', ');

        report += `| ${step.formattedTime} | **${winner.name}** | ${winner.stepScore.toFixed(2)} | ${winner.finalScore.toFixed(2)} | ${evidenceNotes || '(None)'} |\n`;
    });

    return report;
}

import { 
    ChordCandidate, ViterbiNode, HIANote, AuditInputNote, AuditCandidate, AuditFactor,
    INTERVAL_NAMES, DECAY_PER_QUARTER, 
    PENALTY_MISSING_3RD, PENALTY_MISSING_5TH, BONUS_SEVENTH,
    PENALTY_MISSING_7TH, PENALTY_MISSING_6TH, PENALTY_MISSING_ALTERED_5TH,
    BONUS_ROOT_IN_BASS, PENALTY_THIRD_IN_BASS, PENALTY_FIFTH_IN_BASS, PENALTY_SEVENTH_IN_BASS,
    PENALTY_SUBTRACTION, PENALTY_FLOOR,
    WEIGHT_ROLE_ROOT, WEIGHT_ROLE_3RD, WEIGHT_ROLE_5TH, WEIGHT_ROLE_7TH
} from './hiaDefs';
import { getMetricWeight } from './hiaWeights';
import { getFormattedTime } from '../../midiHarmony';

function getRoleWeight(interval: number): number {
    switch(interval) {
        case 0: return WEIGHT_ROLE_ROOT;
        case 3: case 4: return WEIGHT_ROLE_3RD;
        case 6: case 8: return WEIGHT_ROLE_3RD; 
        case 7: return WEIGHT_ROLE_5TH; 
        case 9: return WEIGHT_ROLE_5TH; 
        case 10: case 11: return WEIGHT_ROLE_7TH;
        default: return 1.0;
    }
}

export function scoreCandidate(
    cand: ChordCandidate,
    beatStartTick: number,
    beatEndTick: number,
    beatMidTick: number,
    activeNotes: HIANote[],
    prevNode: ViterbiNode,
    cutoffTick: number,
    suspensionMap: Map<HIANote, boolean>,
    ppq: number,
    tsNum: number,
    tsDenom: number
): { finalScore: number, stepScore: number, auditCandidate: AuditCandidate, inputsLog: AuditInputNote[], assignedNotes: Set<HIANote>, isValid: boolean } {

    // Set Base Quality to 0.9 as requested
    let quality = 0.9;
    const qualityLog: string[] = ["Base 0.9"];
    const assigned = new Set<HIANote>();
    const intervalsPresent = new Set<number>();

    let evidenceSum = 0;
    const evidenceLog: AuditFactor[] = [];

    let penaltySum = 0;
    const penaltyLog: AuditFactor[] = [];

    const inputsLog: AuditInputNote[] = []; 

    const isContinuation = (cand.name === prevNode.chord.name);

    for (const note of activeNotes) {
        const decayVal = (() => {
            const noteEnd = note.ticks + note.durationTicks;
            let distQuarters = 0;
            if (note.ticks >= beatEndTick) distQuarters = (note.ticks - beatEndTick) / ppq; 
            else if (noteEnd < beatMidTick) distQuarters = (beatMidTick - noteEnd) / ppq;
            return Math.max(0, 1 - (DECAY_PER_QUARTER * distQuarters));
        })();

        const isSusp = suspensionMap.get(note) || false;

        const auditNote: AuditInputNote = {
            name: note.name,
            midi: note.midi,
            durationQuarters: note.durationTicks / ppq, 
            metricWeight: getMetricWeight(note.ticks, ppq, tsNum, tsDenom),
            approachModifier: note.approachModifier, 
            decay: decayVal,
            finalSalience: note.baseSalience * decayVal,
            isSuspension: isSusp,
            voiceIndex: note.voiceIndex ?? -1,
            onsetFormatted: getFormattedTime(note.ticks, ppq, tsNum, tsDenom) 
        };

        if (!isContinuation && cutoffTick !== -1) {
            const isQuarterOrLonger = note.durationTicks >= ppq;
            if (note.ticks < cutoffTick && !isQuarterOrLonger) {
                let reason = "Exc. (Passing)";
                if (isSusp) reason = "Exc. (Sus)";
                else if (prevNode.chord.root !== -1) {
                        const prevInterval = (note.midi - prevNode.chord.root + 12) % 12;
                        if (prevNode.chord.intervals.includes(prevInterval)) reason = `Exc. (${prevNode.chord.name})`;
                }
                inputsLog.push({ ...auditNote, finalSalience: 0, isExcluded: true, exclusionReason: reason });
                continue; 
            }
        }

        const rawSalience = auditNote.finalSalience;
        if (rawSalience <= 0) {
             inputsLog.push(auditNote);
             continue;
        }

        const pc = note.midi % 12;
        const interval = (pc - cand.root + 12) % 12;

        if (cand.intervals.includes(interval)) {
            const roleWeight = getRoleWeight(interval);
            const weightedSalience = rawSalience * roleWeight;
            evidenceSum += weightedSalience;
            intervalsPresent.add(interval);
            assigned.add(note);
            evidenceLog.push({ noteName: note.name, label: `${INTERVAL_NAMES[interval]} (x${roleWeight})`, value: weightedSalience });
            inputsLog.push({ ...auditNote, roleWeight, weightedSalience });
        } else if (!isSusp) {
            const penaltyVal = Math.max(rawSalience - PENALTY_SUBTRACTION, PENALTY_FLOOR);
            penaltySum += penaltyVal; 
            penaltyLog.push({ noteName: note.name, label: "Non-CT", value: penaltyVal });
            inputsLog.push(auditNote);
        } else {
             inputsLog.push(auditNote); 
        }
    }

    let isValid = true;

    // Hard Constraint: Root must be present in evidence (not just assumed)
    if (!intervalsPresent.has(0)) {
        isValid = false;
        qualityLog.push("INVALID: No Root");
    }

    if (!intervalsPresent.has(3) && !intervalsPresent.has(4)) {
            quality -= PENALTY_MISSING_3RD;
            qualityLog.push(`No 3rd (-${PENALTY_MISSING_3RD})`);
    }

    const qLower = cand.quality.toLowerCase();
    const isDiminished = qLower.includes('dim') || cand.quality === 'm7b5';
    const isAugmented = qLower.includes('aug');
    const isSeventh = cand.quality.includes('7');
    const isSixth = cand.quality.includes('6');

    if (isDiminished) {
        if (!intervalsPresent.has(6)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No dim5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else if (isAugmented) {
        if (!intervalsPresent.has(8)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No aug5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else {
        if (!intervalsPresent.has(7)) {
            quality -= PENALTY_MISSING_5TH;
            qualityLog.push(`No 5th (-${PENALTY_MISSING_5TH})`);
        }
    }

    if (isSeventh) {
        let has7th = false;
        if (cand.quality === 'dim7') {
            if (intervalsPresent.has(9)) has7th = true; 
        } else if (intervalsPresent.has(10) || intervalsPresent.has(11)) {
            has7th = true; 
        }

        if (!has7th) {
            // Hard Constraint: 7th chords must have 7ths
            isValid = false;
            qualityLog.push("INVALID: No 7th");
        } else {
            quality += BONUS_SEVENTH;
            qualityLog.push(`7th Pres (+${BONUS_SEVENTH})`);
        }
    }

    if (isSixth) {
        // Hard Constraint: 6th chords must have 6ths (Major 6th = 9 semitones)
        if (!intervalsPresent.has(9)) {
            isValid = false;
            qualityLog.push("INVALID: No 6th");
        } else {
            quality -= PENALTY_MISSING_6TH; // Legacy penalty, mostly irrelevant if invalid, but kept for logic consistency if we ever soften constraint
        }
    }

    if (assigned.size > 0) {
        let lowestMidi = Infinity;
        let lowestNote: HIANote | null = null;
        assigned.forEach(n => {
            if (n.midi < lowestMidi) { lowestMidi = n.midi; lowestNote = n; }
        });

        if (lowestNote) {
            const bassInterval = (lowestNote.midi - cand.root + 12) % 12;
            if (bassInterval === 0) {
                quality += BONUS_ROOT_IN_BASS;
                qualityLog.push(`Root Inv (+${BONUS_ROOT_IN_BASS})`);
            }
            else if (bassInterval === 3 || bassInterval === 4) {
                quality -= PENALTY_THIRD_IN_BASS;
                qualityLog.push(`3rd Inv ${lowestNote.name} (-${PENALTY_THIRD_IN_BASS})`);
            }
            else if (bassInterval === 6 || bassInterval === 7 || bassInterval === 8) {
                quality -= PENALTY_FIFTH_IN_BASS;
                qualityLog.push(`5th Inv ${lowestNote.name} (-${PENALTY_FIFTH_IN_BASS})`);
            }
            else if (bassInterval === 9 || bassInterval === 10 || bassInterval === 11) {
                quality -= PENALTY_SEVENTH_IN_BASS;
                qualityLog.push(`7th/6th Inv ${lowestNote.name} (-${PENALTY_SEVENTH_IN_BASS})`);
            }
        }
    }

    // Formula Update: (Evidence * Quality) - Penalty
    // Note: Quality is no longer clamped, so it can be negative.
    const finalStepScore = (evidenceSum * quality) - penaltySum;

    // Accumulate total
    const totalScore = prevNode.score + finalStepScore;

    return {
        finalScore: totalScore,
        stepScore: finalStepScore,
        auditCandidate: {
            name: cand.name,
            qualityScore: quality,
            qualityLog,
            evidenceTotal: evidenceSum,
            evidenceBreakdown: evidenceLog,
            penaltyTotal: penaltySum,
            penaltyBreakdown: penaltyLog,
            pathScore: prevNode.score,
            stepScore: finalStepScore,
            finalScore: totalScore
        },
        inputsLog,
        assignedNotes: assigned,
        isValid
    };
}

import { ChordEvent } from '../../../types';
import { AuditLogStep, AuditCandidate, AuditInputNote, AuditFactor } from './hia/hiaDefs';

const VOICES = ['S', 'A', 'T', 'B'];

function getVoiceCode(idx: number): string {
    if (idx === 0) return 'S';
    if (idx === 1) return 'A';
    if (idx === 2) return 'T';
    if (idx === 3) return 'B';
    return `V${idx+1}`;
}

function formatDuration(quarters: number): string {
    if (Math.abs(quarters - 4.0) < 0.05) return "1/1";
    if (Math.abs(quarters - 3.0) < 0.05) return "1/2.";
    if (Math.abs(quarters - 2.0) < 0.05) return "1/2";
    if (Math.abs(quarters - 1.5) < 0.05) return "1/4.";
    if (Math.abs(quarters - 1.0) < 0.05) return "1/4";
    if (Math.abs(quarters - 0.75) < 0.05) return "1/8.";
    if (Math.abs(quarters - 0.5) < 0.05) return "1/8";
    if (Math.abs(quarters - 0.25) < 0.05) return "1/16";
    return quarters.toFixed(2);
}

function formatHeaderTime(str: string): string {
    return str.replace('M', 'Measure ').replace('B', 'Beat ');
}

function formatFactorLine(f: AuditFactor, sign: string): string {
    const safeName = f.noteName || "Unknown";
    return `- ${sign} ${safeName} (${f.label}) : ${f.value.toFixed(2)}`;
}

function formatWinningChordBlock(cand: AuditCandidate): string {
    let out = `**Winning Chord: ${cand.name}**\n`;

    out += `\n**Chord Notes (Evidence)**\n`;
    if (cand.evidenceBreakdown.length > 0) {
        cand.evidenceBreakdown.forEach(f => out += `${formatFactorLine(f, '+')}\n`);
    }
    out += `= **${cand.evidenceTotal.toFixed(2)}**\n`;

    out += `\n**Non Chord Notes (Penalty)**\n`;
    if (cand.penaltyBreakdown.length > 0) {
        cand.penaltyBreakdown.forEach(f => out += `${formatFactorLine(f, '-')}\n`);
    } else {
        out += `(None)\n`;
    }
    out += `= **-${cand.penaltyTotal.toFixed(2)}**\n`;

    out += `\n**Quality Modifiers** (Applied to Evidence)\n`;
    out += `- Base Quality: 0.90\n`;
    cand.qualityLog.forEach(log => {
        if (log !== "Base 1.0" && log !== "Base 0.9") out += `- ${log}\n`;
    });
    out += `= **${cand.qualityScore.toFixed(2)}**\n`;

    out += `\n**Step Calculation:**\n`;
    out += `Score = (Evidence * Quality) - Penalty\n`;
    out += `Score = (${cand.evidenceTotal.toFixed(2)} * ${cand.qualityScore.toFixed(2)}) - ${cand.penaltyTotal.toFixed(2)}\n`;
    out += `**Step Score:** ${cand.stepScore.toFixed(2)}\n`;
    out += `**Path Accumulation:** ${cand.finalScore.toFixed(2)}\n`;

    return out;
}

function formatRunnersUp(candidates: AuditCandidate[]): string {
    if (!candidates || candidates.length === 0) return "";
    let out = `\n### Runners Up (Alternatives)\n\n`;
    out += `Rank | Chord | Total | Step | Quality | Evid | Pen\n`;
    out += `--- | --- | --- | --- | --- | --- | ---\n`;

    candidates.forEach((c, i) => {
        out += `${i+1} | ${c.name} | ${c.finalScore.toFixed(2)} | ${c.stepScore.toFixed(2)} | ${c.qualityScore.toFixed(2)} | ${c.evidenceTotal.toFixed(2)} | -${c.penaltyTotal.toFixed(2)}\n`;
    });
    return out;
}

export function generateHIAAuditLog(chords: ChordEvent[]): string {
    if (!chords || chords.length === 0) return "";

    // --- PART 1: SUMMARY TABLE ---
    let report = `HIA v2.2 Audit Summary\n\n`;
    report += `| Time | Chord | Score | Path Score | Evidence Notes |\n`;
    report += `| :--- | :--- | :--- | :--- | :--- |\n`;

    chords.forEach((c) => {
        if (!c.debugInfo) return;
        let step: AuditLogStep | null = null;
        try {
            step = JSON.parse(c.debugInfo);
        } catch (e) {
            report += `| ${c.formattedTime} | ERR | - | - | - |\n`;
            return;
        }
        if (!step) return;
        const winner = step.winner;
        const evidenceNotes = winner.evidenceBreakdown.map(f => f.noteName).join(', ');
        report += `| ${step.formattedTime} | **${winner.name}** | ${winner.stepScore.toFixed(2)} | ${winner.finalScore.toFixed(2)} | ${evidenceNotes || '(None)'} |\n`;
    });

    report += `\n\n--------------------------------------------------\n\n`;
    report += `DETAILED DECISION TRACE\n\n`;

    // --- PART 2: DETAILED LOG ---
    let lastReportedScore = 0;

    chords.forEach((c, idx) => {
        if (!c.debugInfo) return;

        let step: AuditLogStep | null = null;
        try {
            step = JSON.parse(c.debugInfo);
        } catch (e) {
            report += `[ERR] Could not parse debug info for ${c.formattedTime}\n`;
            return;
        }

        if (!step) return;

        report += `\n## ${formatHeaderTime(step.formattedTime)}\n\n`;

        report += `### Context\n`;
        report += `**Previous Chord:** ${step.prevChord}\n`;

        // Show how much score was added while the previous chord was held
        const accumulatedInHold = step.winner.pathScore - lastReportedScore;
        if (idx > 0 && accumulatedInHold > 0.01) {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)} (+${accumulatedInHold.toFixed(2)} accumulated during hold)\n`;
        } else {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)}\n`;
        }
        report += `\n`;

        report += `### Inputs\n\n`;
        report += `Voc & Onset | Note | Dur | Met | Appr | Decay | Final Sal | Flags\n`;
        report += `----|------|------|------|------|------|------|-------\n`;

        if (step.inputs.length === 0) {
            report += `(No active inputs)\n`;
        } else {
            step.inputs.forEach((n: AuditInputNote) => {
                const vLabel = getVoiceCode(n.voiceIndex);
                const vocOnset = `${vLabel}: ${n.onsetFormatted}`;
                const safeName = n.name || "???";
                const dur = formatDuration(n.durationQuarters);
                const met = n.metricWeight.toFixed(1);
                const appr = n.approachModifier.toFixed(2); 
                const decay = n.decay.toFixed(2);
                const score = n.finalSalience.toFixed(2);

                let flags = "";
                if (n.isExcluded) flags = n.exclusionReason || "Excluded";
                else if (n.isSuspension) flags = "**Susp**";

                report += `${vocOnset} | ${safeName} | ${dur} | ${met} | ${appr} | ${decay} | ${score} | ${flags}\n`;
            });
        }
        report += `\n`;

        report += `### Winner Selection\n\n`;
        report += formatWinningChordBlock(step.winner);
        lastReportedScore = step.winner.finalScore;

        report += formatRunnersUp(step.runnersUp);
        report += `\n`;
        report += `***\n`;
    });

    return report;
}

import { 
    ChordCandidate, ViterbiNode, HIANote, AuditInputNote, AuditCandidate, AuditFactor,
    INTERVAL_NAMES, DECAY_PER_QUARTER, 
    PENALTY_MISSING_3RD, PENALTY_MISSING_5TH, BONUS_SEVENTH,
    PENALTY_MISSING_7TH, PENALTY_MISSING_6TH, PENALTY_MISSING_ALTERED_5TH,
    BONUS_ROOT_IN_BASS, PENALTY_THIRD_IN_BASS, PENALTY_FIFTH_IN_BASS, PENALTY_SEVENTH_IN_BASS,
    PENALTY_SUBTRACTION, PENALTY_FLOOR,
    WEIGHT_ROLE_ROOT, WEIGHT_ROLE_3RD, WEIGHT_ROLE_5TH, WEIGHT_ROLE_7TH
} from './hiaDefs';
import { getMetricWeight } from './hiaWeights';
import { getFormattedTime } from '../../midiHarmony';

function getRoleWeight(interval: number): number {
    switch(interval) {
        case 0: return WEIGHT_ROLE_ROOT;
        case 3: case 4: return WEIGHT_ROLE_3RD;
        case 6: case 8: return WEIGHT_ROLE_3RD; 
        case 7: return WEIGHT_ROLE_5TH; 
        case 9: return WEIGHT_ROLE_5TH; 
        case 10: case 11: return WEIGHT_ROLE_7TH;
        default: return 1.0;
    }
}

export function scoreCandidate(
    cand: ChordCandidate,
    beatStartTick: number,
    beatEndTick: number,
    beatMidTick: number,
    activeNotes: HIANote[],
    prevNode: ViterbiNode,
    cutoffTick: number,
    suspensionMap: Map<HIANote, boolean>,
    ppq: number,
    tsNum: number,
    tsDenom: number
): { finalScore: number, stepScore: number, auditCandidate: AuditCandidate, inputsLog: AuditInputNote[], assignedNotes: Set<HIANote>, isValid: boolean } {

    // Set Base Quality to 0.9 as requested
    let quality = 0.9;
    const qualityLog: string[] = ["Base 0.9"];
    const assigned = new Set<HIANote>();
    const intervalsPresent = new Set<number>();

    let evidenceSum = 0;
    const evidenceLog: AuditFactor[] = [];

    let penaltySum = 0;
    const penaltyLog: AuditFactor[] = [];

    const inputsLog: AuditInputNote[] = []; 

    const isContinuation = (cand.name === prevNode.chord.name);

    for (const note of activeNotes) {
        const decayVal = (() => {
            const noteEnd = note.ticks + note.durationTicks;
            let distQuarters = 0;
            if (note.ticks >= beatEndTick) distQuarters = (note.ticks - beatEndTick) / ppq; 
            else if (noteEnd < beatMidTick) distQuarters = (beatMidTick - noteEnd) / ppq;
            return Math.max(0, 1 - (DECAY_PER_QUARTER * distQuarters));
        })();

        const isSusp = suspensionMap.get(note) || false;

        const auditNote: AuditInputNote = {
            name: note.name,
            midi: note.midi,
            durationQuarters: note.durationTicks / ppq, 
            metricWeight: getMetricWeight(note.ticks, ppq, tsNum, tsDenom),
            approachModifier: note.approachModifier, 
            decay: decayVal,
            finalSalience: note.baseSalience * decayVal,
            isSuspension: isSusp,
            voiceIndex: note.voiceIndex ?? -1,
            onsetFormatted: getFormattedTime(note.ticks, ppq, tsNum, tsDenom) 
        };

        if (!isContinuation && cutoffTick !== -1) {
            const isQuarterOrLonger = note.durationTicks >= ppq;
            if (note.ticks < cutoffTick && !isQuarterOrLonger) {
                let reason = "Exc. (Passing)";
                if (isSusp) reason = "Exc. (Sus)";
                else if (prevNode.chord.root !== -1) {
                        const prevInterval = (note.midi - prevNode.chord.root + 12) % 12;
                        if (prevNode.chord.intervals.includes(prevInterval)) reason = `Exc. (${prevNode.chord.name})`;
                }
                inputsLog.push({ ...auditNote, finalSalience: 0, isExcluded: true, exclusionReason: reason });
                continue; 
            }
        }

        const rawSalience = auditNote.finalSalience;
        if (rawSalience <= 0) {
             inputsLog.push(auditNote);
             continue;
        }

        const pc = note.midi % 12;
        const interval = (pc - cand.root + 12) % 12;

        if (cand.intervals.includes(interval)) {
            const roleWeight = getRoleWeight(interval);
            const weightedSalience = rawSalience * roleWeight;
            evidenceSum += weightedSalience;
            intervalsPresent.add(interval);
            assigned.add(note);
            evidenceLog.push({ noteName: note.name, label: `${INTERVAL_NAMES[interval]} (x${roleWeight})`, value: weightedSalience });
            inputsLog.push({ ...auditNote, roleWeight, weightedSalience });
        } else if (!isSusp) {
            const penaltyVal = Math.max(rawSalience - PENALTY_SUBTRACTION, PENALTY_FLOOR);
            penaltySum += penaltyVal; 
            penaltyLog.push({ noteName: note.name, label: "Non-CT", value: penaltyVal });
            inputsLog.push(auditNote);
        } else {
             inputsLog.push(auditNote); 
        }
    }

    let isValid = true;

    // Hard Constraint: Root must be present in evidence (not just assumed)
    if (!intervalsPresent.has(0)) {
        isValid = false;
        qualityLog.push("INVALID: No Root");
    }

    if (!intervalsPresent.has(3) && !intervalsPresent.has(4)) {
            quality -= PENALTY_MISSING_3RD;
            qualityLog.push(`No 3rd (-${PENALTY_MISSING_3RD})`);
    }

    const qLower = cand.quality.toLowerCase();
    const isDiminished = qLower.includes('dim') || cand.quality === 'm7b5';
    const isAugmented = qLower.includes('aug');
    const isSeventh = cand.quality.includes('7');
    const isSixth = cand.quality.includes('6');

    if (isDiminished) {
        if (!intervalsPresent.has(6)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No dim5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else if (isAugmented) {
        if (!intervalsPresent.has(8)) {
            quality -= PENALTY_MISSING_ALTERED_5TH;
            qualityLog.push(`No aug5 (-${PENALTY_MISSING_ALTERED_5TH})`);
        }
    } else {
        if (!intervalsPresent.has(7)) {
            quality -= PENALTY_MISSING_5TH;
            qualityLog.push(`No 5th (-${PENALTY_MISSING_5TH})`);
        }
    }

    if (isSeventh) {
        let has7th = false;
        if (cand.quality === 'dim7') {
            if (intervalsPresent.has(9)) has7th = true; 
        } else if (intervalsPresent.has(10) || intervalsPresent.has(11)) {
            has7th = true; 
        }

        if (!has7th) {
            // Hard Constraint: 7th chords must have 7ths
            isValid = false;
            qualityLog.push("INVALID: No 7th");
        } else {
            quality += BONUS_SEVENTH;
            qualityLog.push(`7th Pres (+${BONUS_SEVENTH})`);
        }
    }

    if (isSixth) {
        // Hard Constraint: 6th chords must have 6ths (Major 6th = 9 semitones)
        if (!intervalsPresent.has(9)) {
            isValid = false;
            qualityLog.push("INVALID: No 6th");
        } else {
            // We removed the legacy penalty since invalid makes it moot, but conceptually 
            // the check above handles it.
        }
    }

    if (assigned.size > 0) {
        let lowestMidi = Infinity;
        let lowestNote: HIANote | null = null;
        assigned.forEach(n => {
            if (n.midi < lowestMidi) { lowestMidi = n.midi; lowestNote = n; }
        });

        if (lowestNote) {
            const bassInterval = (lowestNote.midi - cand.root + 12) % 12;
            if (bassInterval === 0) {
                quality += BONUS_ROOT_IN_BASS;
                qualityLog.push(`Root Inv (+${BONUS_ROOT_IN_BASS})`);
            }
            else if (bassInterval === 3 || bassInterval === 4) {
                quality -= PENALTY_THIRD_IN_BASS;
                qualityLog.push(`3rd Inv ${lowestNote.name} (-${PENALTY_THIRD_IN_BASS})`);
            }
            else if (bassInterval === 6 || bassInterval === 7 || bassInterval === 8) {
                quality -= PENALTY_FIFTH_IN_BASS;
                qualityLog.push(`5th Inv ${lowestNote.name} (-${PENALTY_FIFTH_IN_BASS})`);
            }
            else if (bassInterval === 9 || bassInterval === 10 || bassInterval === 11) {
                quality -= PENALTY_SEVENTH_IN_BASS;
                qualityLog.push(`7th/6th Inv ${lowestNote.name} (-${PENALTY_SEVENTH_IN_BASS})`);
            }
        }
    }

    // Formula Update: (Evidence * Quality) - Penalty
    // Note: Quality is no longer clamped, so it can be negative.
    const finalStepScore = (evidenceSum * quality) - penaltySum;

    // Accumulate total
    const totalScore = prevNode.score + finalStepScore;

    return {
        finalScore: totalScore,
        stepScore: finalStepScore,
        auditCandidate: {
            name: cand.name,
            qualityScore: quality,
            qualityLog,
            evidenceTotal: evidenceSum,
            evidenceBreakdown: evidenceLog,
            penaltyTotal: penaltySum,
            penaltyBreakdown: penaltyLog,
            pathScore: prevNode.score,
            stepScore: finalStepScore,
            finalScore: totalScore
        },
        inputsLog,
        assignedNotes: assigned,
        isValid
    };
}

import { ChordEvent } from '../../../types';
import { AuditLogStep, AuditCandidate, AuditInputNote, AuditFactor } from './hia/hiaDefs';

const VOICES = ['S', 'A', 'T', 'B'];

function getVoiceCode(idx: number): string {
    if (idx === 0) return 'S';
    if (idx === 1) return 'A';
    if (idx === 2) return 'T';
    if (idx === 3) return 'B';
    return `V${idx+1}`;
}

function formatDuration(quarters: number): string {
    if (Math.abs(quarters - 4.0) < 0.05) return "1/1";
    if (Math.abs(quarters - 3.0) < 0.05) return "1/2.";
    if (Math.abs(quarters - 2.0) < 0.05) return "1/2";
    if (Math.abs(quarters - 1.5) < 0.05) return "1/4.";
    if (Math.abs(quarters - 1.0) < 0.05) return "1/4";
    if (Math.abs(quarters - 0.75) < 0.05) return "1/8.";
    if (Math.abs(quarters - 0.5) < 0.05) return "1/8";
    if (Math.abs(quarters - 0.25) < 0.05) return "1/16";
    return quarters.toFixed(2);
}

function formatHeaderTime(str: string): string {
    return str.replace('M', 'Measure ').replace('B', 'Beat ');
}

function formatFactorLine(f: AuditFactor, sign: string): string {
    const safeName = f.noteName || "Unknown";
    return `- ${sign} ${safeName} (${f.label}) : ${f.value.toFixed(2)}`;
}

function formatWinningChordBlock(cand: AuditCandidate): string {
    let out = `**Winning Chord: ${cand.name}**\n`;

    out += `\n**Chord Notes (Evidence)**\n`;
    if (cand.evidenceBreakdown.length > 0) {
        cand.evidenceBreakdown.forEach(f => out += `${formatFactorLine(f, '+')}\n`);
    }
    out += `= **${cand.evidenceTotal.toFixed(2)}**\n`;

    out += `\n**Non Chord Notes (Penalty)**\n`;
    if (cand.penaltyBreakdown.length > 0) {
        cand.penaltyBreakdown.forEach(f => out += `${formatFactorLine(f, '-')}\n`);
    } else {
        out += `(None)\n`;
    }
    out += `= **-${cand.penaltyTotal.toFixed(2)}**\n`;

    out += `\n**Quality Modifiers** (Applied to Evidence)\n`;
    out += `- Base Quality: 0.90\n`;
    cand.qualityLog.forEach(log => {
        if (log !== "Base 1.0" && log !== "Base 0.9") out += `- ${log}\n`;
    });
    out += `= **${cand.qualityScore.toFixed(2)}**\n`;

    out += `\n**Step Calculation:**\n`;
    out += `Score = (Evidence * Quality) - Penalty\n`;
    out += `Score = (${cand.evidenceTotal.toFixed(2)} * ${cand.qualityScore.toFixed(2)}) - ${cand.penaltyTotal.toFixed(2)}\n`;
    out += `**Step Score:** ${cand.stepScore.toFixed(2)}\n`;
    out += `**Path Accumulation:** ${cand.finalScore.toFixed(2)}\n`;

    return out;
}

function formatRunnersUp(candidates: AuditCandidate[]): string {
    if (!candidates || candidates.length === 0) return "";
    let out = `\n### Runners Up (Alternatives)\n\n`;
    out += `Rank | Chord | Total | Step | Quality | Evid | Pen\n`;
    out += `--- | --- | --- | --- | --- | --- | ---\n`;

    candidates.forEach((c, i) => {
        out += `${i+1} | ${c.name} | ${c.finalScore.toFixed(2)} | ${c.stepScore.toFixed(2)} | ${c.qualityScore.toFixed(2)} | ${c.evidenceTotal.toFixed(2)} | -${c.penaltyTotal.toFixed(2)}\n`;
    });
    return out;
}

export function generateHIAAuditLog(chords: ChordEvent[]): string {
    if (!chords || chords.length === 0) return "";

    // --- PART 1: SUMMARY TABLE ---
    let report = `HIA v2.2 Audit Summary\n\n`;
    report += `| Time | Winning Chord | Step Score | Path Score | Top Alternatives |\n`;
    report += `| :--- | :--- | :--- | :--- | :--- |\n`;

    chords.forEach((c) => {
        if (!c.debugInfo) return;
        let step: AuditLogStep | null = null;
        try {
            step = JSON.parse(c.debugInfo);
        } catch (e) {
            report += `| ${c.formattedTime} | ERR | - | - | - |\n`;
            return;
        }
        if (!step) return;
        const winner = step.winner;
        const alts = step.runnersUp.slice(0, 3).map(r => `${r.name} (${r.stepScore.toFixed(1)})`).join(', ');

        report += `| ${step.formattedTime} | **${winner.name}** | ${winner.stepScore.toFixed(2)} | ${winner.finalScore.toFixed(2)} | ${alts || '(None)'} |\n`;
    });

    report += `\n\n--------------------------------------------------\n\n`;
    report += `DETAILED DECISION TRACE\n\n`;

    // --- PART 2: DETAILED LOG ---
    let lastReportedScore = 0;

    chords.forEach((c, idx) => {
        if (!c.debugInfo) return;

        let step: AuditLogStep | null = null;
        try {
            step = JSON.parse(c.debugInfo);
        } catch (e) {
            report += `[ERR] Could not parse debug info for ${c.formattedTime}\n`;
            return;
        }

        if (!step) return;

        report += `\n## ${formatHeaderTime(step.formattedTime)}\n\n`;

        report += `### Context\n`;
        report += `**Previous Chord:** ${step.prevChord}\n`;

        // Show how much score was added while the previous chord was held
        const accumulatedInHold = step.winner.pathScore - lastReportedScore;
        if (idx > 0 && accumulatedInHold > 0.01) {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)} (+${accumulatedInHold.toFixed(2)} accumulated during hold)\n`;
        } else {
            report += `**Incoming Path Score:** ${step.winner.pathScore.toFixed(2)}\n`;
        }
        report += `\n`;

        report += `### Inputs\n\n`;
        report += `Voc & Onset | Note | Dur | Met | Appr | Decay | Final Sal | Flags\n`;
        report += `----|------|------|------|------|------|------|-------\n`;

        if (step.inputs.length === 0) {
            report += `(No active inputs)\n`;
        } else {
            step.inputs.forEach((n: AuditInputNote) => {
                const vLabel = getVoiceCode(n.voiceIndex);
                const vocOnset = `${vLabel}: ${n.onsetFormatted}`;
                const safeName = n.name || "???";
                const dur = formatDuration(n.durationQuarters);
                const met = n.metricWeight.toFixed(1);
                const appr = n.approachModifier.toFixed(2); 
                const decay = n.decay.toFixed(2);
                const score = n.finalSalience.toFixed(2);

                let flags = "";
                if (n.isExcluded) flags = n.exclusionReason || "Excluded";
                else if (n.isSuspension) flags = "**Susp**";

                report += `${vocOnset} | ${safeName} | ${dur} | ${met} | ${appr} | ${decay} | ${score} | ${flags}\n`;
            });
        }
        report += `\n`;

        report += `### Winner Selection\n\n`;
        report += formatWinningChordBlock(step.winner);
        lastReportedScore = step.winner.finalScore;

        report += formatRunnersUp(step.runnersUp);
        report += `\n`;
        report += `***\n`;
    });

    return report;
}

import { RawNote, ChordEvent } from '../../../types';
import { getFormattedTime } from '../midiHarmony';
import { getStrictPitchName } from '../midiSpelling';
import { 
    BEAM_WIDTH, HIANote, BeatWindow, ViterbiNode
} from './hia/hiaDefs';
import { calculateBaseSalience } from './hia/hiaWeights';
import { getPhysicalBass, buildVoiceLinks, isSuspension } from './hia/hiaContext';
import { generateCandidates } from './hia/hiaCandidates';
import { scoreCandidate } from './hia/hiaScoring';

export function detectChordsHIA(notes: RawNote[], ppq: number, tsNum: number, tsDenom: number): ChordEvent[] {
    const sortedNotes = [...notes].sort((a,b) => a.ticks - b.ticks);
    const voiceTracker: Record<number, number> = {};

    const hiaNotes: HIANote[] = sortedNotes.map(n => {
        const v = n.voiceIndex ?? 0;
        const prev = voiceTracker[v];
        voiceTracker[v] = n.midi;
        return calculateBaseSalience(n, ppq, tsNum, tsDenom, prev);
    });

    const noteLinks = buildVoiceLinks(hiaNotes); 

    const beats: BeatWindow[] = [];
    const maxTick = Math.max(...hiaNotes.map(n => n.ticks + n.durationTicks));
    const ticksPerBeat = ppq; 
    const totalBeats = Math.ceil(maxTick / ticksPerBeat);

    for (let i = 0; i < totalBeats; i++) {
        const start = i * ticksPerBeat;
        const end = (i + 1) * ticksPerBeat;
        const mid = start + (ticksPerBeat / 2);
        const lookbackLimit = start - (4 * ppq);
        const lookaheadLimit = end + (2 * ticksPerBeat); 
        const active = hiaNotes.filter(n => {
            const noteEnd = n.ticks + n.durationTicks;
            return n.ticks < lookaheadLimit && noteEnd > lookbackLimit;
        });
        beats.push({ index: i, startTick: start, midTick: mid, endTick: end, activeNotes: active });
    }

    let beam: ViterbiNode[] = [{ 
        chord: { root: -1, quality: 'None', intervals: [], bass: -1, baselineQ: 0, name: 'Start' }, 
        score: 0, path: [], assignedNotes: new Set<HIANote>(),
        audit: { 
            tick: 0, formattedTime: '0:0', prevChord: 'None', inputs: [], 
            winner: { name: 'Start', qualityScore: 0, qualityLog: [], evidenceTotal: 0, evidenceBreakdown: [], penaltyTotal: 0, penaltyBreakdown: [], pathScore: 0, stepScore: 0, finalScore: 0 },
            runnersUp: [] 
        },
        _prevNodeIdx: -1
    }];

    for (const beat of beats) {
        const nextBeam: ViterbiNode[] = [];
        const presentRoots = new Set<number>();
        beat.activeNotes.forEach(n => presentRoots.add(n.midi % 12));

        const prevBassMidi = getPhysicalBass(sortedNotes, beat.startTick - 1);
        const currBassMidi = getPhysicalBass(sortedNotes, beat.startTick);
        const suspensionMap = new Map<HIANote, boolean>();

        if (beat.activeNotes.length >= 2) {
            beat.activeNotes.forEach(n => {
                const links = noteLinks.get(n) || { prev: null, next: null };
                const isSusp = isSuspension(n, beat.startTick, beat.endTick, prevBassMidi, currBassMidi, links);
                if (isSusp) suspensionMap.set(n, true);
            });
        }

        if (presentRoots.size === 0) {
            nextBeam.push(...beam.map(b => ({
                ...b, 
                score: b.score, 
                path: [...b.path, b], 
                assignedNotes: new Set<HIANote>(),
                audit: { 
                    tick: beat.startTick, 
                    formattedTime: getFormattedTime(beat.startTick, ppq, tsNum, tsDenom),
                    prevChord: b.chord.name,
                    inputs: [],
                    winner: { name: 'Silence', qualityScore: 0, qualityLog: [], evidenceTotal: 0, evidenceBreakdown: [], penaltyTotal: 0, penaltyBreakdown: [], pathScore: b.score, stepScore: 0, finalScore: b.score },
                    runnersUp: []
                },
                _prevNodeIdx: b._prevNodeIdx
            })));
            beam = nextBeam;
            continue;
        }

        const candidates = generateCandidates(presentRoots);
        const candidatesScores: ViterbiNode[] = [];

        beam.forEach((prevNode, prevIdx) => {
            let cutoffTick = -1;
            if (prevNode.assignedNotes.size > 0) {
                const sortedPrev = Array.from(prevNode.assignedNotes).sort((a,b) => {
                    if (a.ticks !== b.ticks) return a.ticks - b.ticks;
                    return (a.ticks + a.durationTicks) - (b.ticks + b.durationTicks);
                });
                const finalNote = sortedPrev[sortedPrev.length - 1];
                cutoffTick = finalNote.ticks + (finalNote.durationTicks / 2);
            }

            for (const cand of candidates) {
                const result = scoreCandidate(
                    cand, 
                    beat.startTick, 
                    beat.endTick, 
                    beat.midTick, 
                    beat.activeNotes, 
                    prevNode, 
                    cutoffTick, 
                    suspensionMap, 
                    ppq, tsNum, tsDenom
                );

                // Exclude Invalid Candidates (Missing Root / Missing 7th)
                if (!result.isValid) continue;

                candidatesScores.push({
                    chord: cand, 
                    score: result.finalScore, 
                    path: [...prevNode.path, prevNode],
                    assignedNotes: result.assignedNotes,
                    audit: {
                        tick: beat.startTick,
                        formattedTime: getFormattedTime(beat.startTick, ppq, tsNum, tsDenom),
                        prevChord: prevNode.chord.name,
                        inputs: result.inputsLog,
                        winner: result.auditCandidate,
                        runnersUp: []
                    },
                    _prevNodeIdx: prevIdx
                });
            }
        });

        candidatesScores.sort((a,b) => b.score - a.score);
        const seen = new Set<string>();
        const chosenNodes: ViterbiNode[] = [];

        for (const cs of candidatesScores) {
            if (seen.size >= BEAM_WIDTH) break;
            if (!seen.has(cs.chord.name)) { chosenNodes.push(cs); seen.add(cs.chord.name); }
        }

        chosenNodes.forEach(chosen => {
            const siblings = candidatesScores.filter(c => c.chord.name !== chosen.chord.name);
            chosen.audit.runnersUp = siblings.slice(0, 3).map(s => s.audit.winner);
        });

        if (chosenNodes.length === 0) {
             nextBeam.push(...beam.map(b => ({ ...b, path: [...b.path, b] })));
             beam = nextBeam;
        } else {
             beam = chosenNodes;
        }
    }

    const bestFinal = beam[0];
    if (!bestFinal) return [];

    const trace = [...bestFinal.path, bestFinal];
    trace.shift(); 

    const events: ChordEvent[] = [];

    // NOTE: Removed deduplication logic. 
    // We now output an event for EVERY node in the path (every beat) 
    // so the audit log is complete. 
    // The visual report generator will handle condensing repeated chords.

    trace.forEach((node, i) => {
        const beat = beats[i]; 
        const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
        const measure = Math.floor(beat.startTick / ticksPerMeasure) + 1;
        const uniqueConst = Array.from(new Set(Array.from(node.assignedNotes).map(n => n.name)));

        const structuredDebug = JSON.stringify(node.audit);

        const evt: ChordEvent = {
            timestamp: beat.startTick / ppq, measure, formattedTime: getFormattedTime(beat.startTick, ppq, tsNum, tsDenom),
            name: node.chord.name, root: getStrictPitchName(node.chord.root).replace(/\d/g,''), quality: node.chord.quality,
            bass: getStrictPitchName(node.chord.bass).replace(/\d/g,''), ticks: beat.startTick,
            constituentNotes: uniqueConst, missingNotes: [], alternatives: [], debugInfo: structuredDebug
        };
        events.push(evt);
    });
    return events;
}

import { Midi } from '@tonejs/midi';
import { TrackAnalysisData, NoteValueStat, ConversionOptions, RawNote, PitchAnalysisMode, PitchStats } from '../../types';
import { detectAndTagOrnaments, NOTE_NAMES } from './midiCore';
import { distributeToVoices } from './midiVoices';
import { detectChordsSustain, detectChordsAttack } from './midiHarmony';
import { copyAndTransformTrackEvents } from './midiPipeline';
import { calculateTransformationStats } from './analysis/transformationAnalysis';
